document.addEventListener("DOMContentLoaded",()=>{const navLinks=document.querySelectorAll(".nav-link");const sections=document.querySelectorAll(".section");navLinks.forEach(link=>{link.addEventListener("click",e=>{e.preventDefault();const targetId=link.getAttribute("data-target");navLinks.forEach(l=>l.classList.remove("active"));link.classList.add("active");sections.forEach(section=>{section.classList.remove("active");if(section.id===targetId){section.classList.add("active")}})})});const potencia20minInput=document.getElementById("potencia-20min");const pesoAtletaInput=document.getElementById("peso-atleta");const fcMedia20minInput=document.getElementById("fc-media-20min");const calcularFtpBtn=document.getElementById("calcular-ftp");const ftpValueElement=document.getElementById("ftp-value");const wattsKgValueElement=document.getElementById("watts-kg-value");calcularFtpBtn.addEventListener("click",()=>{if(!potencia20minInput.value||!pesoAtletaInput.value){alert("Por favor, insira a potência de 20 minutos e o peso do atleta.");return}const potencia20min=parseFloat(potencia20minInput.value);const pesoAtleta=parseFloat(pesoAtletaInput.value);const ftp=Math.round(potencia20min*.95);const wattsKg=(ftp/pesoAtleta).toFixed(2);ftpValueElement.textContent=`${ftp} watts`;wattsKgValueElement.textContent=`${wattsKg} w/kg`});const formTeste=document.getElementById("form-teste");formTeste.addEventListener("submit",e=>{e.preventDefault();if(ftpValueElement.textContent==="-"){alert("Por favor, calcule o FTP antes de gerar o relatório.");return}if(!formTeste.checkValidity()){formTeste.reportValidity();return}const alunoNome=document.getElementById("aluno-nome").value;const dataTeste=document.getElementById("data-teste").value;const pesoAtleta=parseFloat(pesoAtletaInput.value);const potencia20min=parseFloat(potencia20minInput.value);const fcMedia20min=fcMedia20minInput.value?parseInt(fcMedia20minInput.value):null;const ftp=parseInt(ftpValueElement.textContent.replace(" watts",""));const wattsKg=parseFloat(wattsKgValueElement.textContent.replace(" w/kg",""));const zonasPotencia=calcularZonasPotencia(ftp);const zonasFC=fcMedia20min?calcularZonasFC(fcMedia20min):null;const recomendacoesProvas=calcularRecomendacoesProvas(ftp);const testeData={alunoNome:alunoNome,dataTeste:dataTeste,pesoAtleta:pesoAtleta,potencia20min:potencia20min,fcMedia20min:fcMedia20min,ftp:ftp,wattsKg:wattsKg,zonasPotencia:zonasPotencia,zonasFC:zonasFC,recomendacoesProvas:recomendacoesProvas,tipoTeste:"ftp-ciclismo"};gerarRelatorio(testeData)});function calcularZonasPotencia(ftp){return[{zona:"Z1",nome:"Recuperação Ativa",min:Math.round(ftp*.4),max:Math.round(ftp*.55)},{zona:"Z2",nome:"Resistência",min:Math.round(ftp*.56),max:Math.round(ftp*.75)},{zona:"Z3",nome:"Tempo/Ritmo",min:Math.round(ftp*.76),max:Math.round(ftp*.9)},{zona:"Z4",nome:"Limiar",min:Math.round(ftp*.91),max:Math.round(ftp*1.05)},{zona:"Z5",nome:"VO2 Max",min:Math.round(ftp*1.06),max:Math.round(ftp*1.2)},{zona:"Z6",nome:"Capacidade Anaeróbica",min:Math.round(ftp*1.21),max:Math.round(ftp*1.5)},{zona:"Z7",nome:"Potência Neuromuscular",min:Math.round(ftp*1.51),max:Math.round(ftp*1.8)}]}function calcularZonasFC(fcMedia){return[{zona:"Z1",nome:"Recuperação Ativa",min:Math.round(fcMedia*.75),max:Math.round(fcMedia*.81)},{zona:"Z2",nome:"Resistência",min:Math.round(fcMedia*.8101),max:Math.round(fcMedia*.89)},{zona:"Z3",nome:"Tempo/Ritmo",min:Math.round(fcMedia*.8901),max:Math.round(fcMedia*.93)},{zona:"Z4",nome:"Limiar",min:Math.round(fcMedia*.9301),max:Math.round(fcMedia*.99)},{zona:"Z5",nome:"VO2 Max",min:Math.round(fcMedia*.9901),max:Math.round(fcMedia*1.02)},{zona:"Z6",nome:"Capacidade Anaeróbica",min:Math.round(fcMedia*1.0201),max:Math.round(fcMedia*1.08)}]}function calcularRecomendacoesProvas(ftp){return[{prova:"Sprint (até 1h)",potenciaMin:Math.round(ftp*.88),potenciaMax:Math.round(ftp*.98),percentualMin:88,percentualMax:98},{prova:"Standard/Olímpico (1-2h)",potenciaMin:Math.round(ftp*.83),potenciaMax:Math.round(ftp*.9),percentualMin:83,percentualMax:90},{prova:"Half Distance (2-4h)",potenciaMin:Math.round(ftp*.75),potenciaMax:Math.round(ftp*.85),percentualMin:75,percentualMax:85},{prova:"Full Distance (4-8h)",potenciaMin:Math.round(ftp*.65),potenciaMax:Math.round(ftp*.75),percentualMin:65,percentualMax:75}]}});function gerarRelatorio(data){const jsonData=JSON.stringify(data);const encodedData=encodeURIComponent(jsonData);window.open(`report-ftp.html?data=${encodedData}`,"_blank")}